args.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?battleLabel ?warLabel ?victor WHERE {
  VALUES ?war { wd:Q1151913 wd:Q916495 wd:Q1342568 }
  ?battle wdt:P361 ?war ;
          rdfs:label ?battleLabel ;
          wdt:P1329 ?result .
  ?war rdfs:label ?warLabel .
  FILTER(LANG(?battleLabel) = "en")
  FILTER(LANG(?warLabel) = "en")
  BIND(IF(regex(?result, "english", "i"), "English",
         IF(regex(?result, "dutch", "i"), "Dutch", "Unknown")) AS ?victor)
  FILTER(?victor != "Unknown")
}
ORDER BY ?warLabel

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?battleLabel ?warLabel ?result WHERE {
  VALUES ?war { wd:Q1151913 wd:Q916495 wd:Q1342568 }
  ?battle wdt:P361 ?war .
  ?battle rdfs:label ?battleLabel .
  ?war rdfs:label ?warLabel .
  OPTIONAL { ?battle wdt:P1329 ?result . }
  FILTER(LANG(?battleLabel) = "en")
  FILTER(LANG(?warLabel) = "en")
}
ORDER BY ?warLabel
